import { useState, useRef, useEffect, useCallback } from 'react';
import { useAuth } from '../../../contexts/AuthContext';
import { useChat } from '../../../hooks/useChat';

interface DiaryModalProps {
  isOpen: boolean;
  onClose: () => void;
  mode: 'diary' | 'survey';
}

const DiaryModal = ({ isOpen, onClose, mode }: DiaryModalProps) => {
  const { user } = useAuth(); //
  const { messages, isLoading, startChat, sendMessage, resetChat } = useChat();
  const [input, setInput] = useState('');
  
  const msgEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // 모달 열릴 때 API를 통한 채팅 세션 시작
  useEffect(() => {
    if (isOpen && user?.id) {
      startChat(user.id); //
      setTimeout(() => inputRef.current?.focus(), 300);
    } else if (!isOpen) {
      resetChat();
      setInput('');
    }
  }, [isOpen, user?.id, startChat, resetChat]);

  // 메시지 추가 시 아래로 자동 스크롤
  useEffect(() => {
    msgEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, isLoading]);

  // ─── 수정된 부분: sendMessage 호출 시 user.id 전달 ───
  const handleSend = useCallback(async () => {
    const text = input.trim();
    if (!text || !user?.id || isLoading) return;

    setInput(''); // 입력 필드 즉시 초기화 (Optimistic UI)
    
    /**
     * 💡 변경됨: 훅의 정의에 따라 userId를 두 번째 인자로 넘겨줍니다.
     * 이를 통해 /api/chat-sessions/{sessionId}/messages?userId=... 요청이 완성됩니다.
     */
    await sendMessage(text, user.id); //
  }, [input, user?.id, isLoading, sendMessage]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] flex items-end justify-center">
      {/* 딤 오버레이 */}
      <div
        className="absolute inset-0 bg-black/30 backdrop-blur-[2px]"
        onClick={onClose}
      />

      {/* 모달 패널 */}
      <div className="relative w-full max-w-[480px] h-[88vh] flex flex-col bg-white border border-slate-200 rounded-t-[28px] shadow-2xl overflow-hidden">
        {/* 핸들 */}
        <div className="flex justify-center pt-3 pb-1 flex-shrink-0">
          <div className="w-10 h-1 rounded-full bg-slate-300" />
        </div>

        {/* 헤더 */}
        <div className="flex items-center justify-between px-5 py-3 border-b border-slate-100 flex-shrink-0">
          <div className="flex items-center gap-2.5">
            <div className="w-8 h-8 rounded-full bg-slate-50 flex items-center justify-center text-base border border-slate-200 shadow-sm">
              {mode === 'diary' ? '📔' : '📋'}
            </div>
            <div>
              <h3 className="text-[15px] font-bold text-slate-800 leading-tight">
                {mode === 'diary' ? '오늘 일기 쓰기' : '마음 설문'}
              </h3>
              <p className="text-[11px] text-brand-orange-dark font-medium">AI 감정 코치와 대화 중</p>
            </div>
          </div>
          <button
            onClick={onClose}
            className="w-8 h-8 flex items-center justify-center rounded-full bg-slate-100 text-slate-500 hover:bg-slate-200 transition-colors text-lg cursor-pointer border-none"
          >
            ×
          </button>
        </div>

        {/* 채팅 영역 */}
        <div className="flex-1 overflow-y-auto px-4 py-4 flex flex-col gap-3 no-scrollbar bg-[#0f0f1e]">
          {messages.map((msg) => (
            <div
              key={msg.id}
              className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}
            >
              {msg.role === 'ai' && (
                <div className="w-7 h-7 rounded-full bg-slate-50 border border-slate-200 shadow-sm flex items-center justify-center text-sm flex-shrink-0 mr-2 mt-0.5">
                  🤖
                </div>
              )}

              <div
                className={[
                  'max-w-[78%] rounded-[16px] px-4 py-3 text-[14px] leading-relaxed whitespace-pre-line shadow-sm border border-transparent',
                  msg.role === 'ai'
                    ? 'bg-slate-50 border-slate-200 text-slate-800 rounded-tl-sm'
                    : 'bg-gradient-to-br from-brand-orange to-brand-orange-dark text-white rounded-tr-sm shadow-[0_4px_12px_rgba(255,107,0,0.2)]',
                ].join(' ')}
              >
                {msg.text}
              </div>
            </div>
          ))}

          {isLoading && (
            <div className="flex justify-start">
              <div className="w-7 h-7 rounded-full bg-slate-50 border border-slate-200 shadow-sm flex items-center justify-center text-sm flex-shrink-0 mr-2 mt-0.5">
                🤖
              </div>
              <div className="bg-slate-50 border border-slate-200 rounded-[16px] rounded-tl-sm px-4 py-3.5 flex items-center gap-1 shadow-sm">
                {[0, 1, 2].map((i) => (
                  <span
                    key={i}
                    className="w-1.5 h-1.5 rounded-full bg-slate-400 animate-bounce"
                    style={{ animationDelay: `${i * 0.15}s` }}
                  />
                ))}
              </div>
            </div>
          )}
          <div ref={msgEndRef} />
        </div>

        {/* 입력 창 */}
        <div className="px-4 pb-6 pt-3 border-t border-slate-100 flex-shrink-0">
          <div className="flex items-center gap-2.5 bg-white border border-slate-200 shadow-inner rounded-2xl px-4 py-2.5">
            <input
              ref={inputRef}
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && !e.nativeEvent.isComposing) {
                  handleSend();
                }
              }}
              placeholder="마음을 자유롭게 적어보세요..."
              className="flex-1 bg-transparent text-slate-800 text-[14px] outline-none placeholder:text-slate-400 font-sans"
            />
            <button
              onClick={handleSend}
              disabled={!input.trim() || isLoading}
              className={[
                'w-9 h-9 rounded-xl flex items-center justify-center flex-shrink-0 transition-all duration-200 cursor-pointer border-none text-base',
                input.trim() && !isTyping
                  ? 'bg-gradient-to-br from-brand-orange to-brand-orange-dark text-white shadow-[0_4px_12px_rgba(255,107,0,0.3)]'
                  : 'bg-slate-100 text-slate-400',
              ].join(' ')}
            >
              ↑
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DiaryModal;

import { useRef } from 'react';
import type { Mesh } from 'three';
import { motion } from 'framer-motion-3d';
import { Edges } from '@react-three/drei';

const BLOCK_MATERIAL: Record<
  string,
  { color: string; roughness: number }
> = {
  standard: { color: '#dcb38a', roughness: 0.9 }, // 밝은 나무색
  stress:   { color: '#e07a5f', roughness: 0.8 }, // 뮤트된 코랄 오렌지
  joy:      { color: '#f4f1de', roughness: 0.8 }, // 크림 베이지
  anxiety:  { color: '#81b29a', roughness: 0.8 }, // 뮤트된 민트 그린
  sadness:  { color: '#3d405b', roughness: 0.9 }, // 딥 네이비
  anger:    { color: '#c1121f', roughness: 0.9 }, // 딥 레드
  calm:     { color: '#eef4ed', roughness: 0.8 }, // 옅은 민트
  fatigue:  { color: '#8d99ae', roughness: 0.9 }, // 슬레이트 그레이
};

export interface JengaBlock3DProps {
  position: [number, number, number];
  rotation: [number, number, number];
  blockType?: string;
  isCollapsed?: boolean;
  floorIndex: number; 
  blockIndex: number; // Stagger delay를 위해 사용 (전체 인덱스)
  collapsedOffset?: [number, number, number];
  collapsedRotation?: [number, number, number];
}

const JengaBlock3D = ({
  position,
  rotation,
  blockType = 'standard',
  isCollapsed = false,
  blockIndex,
  collapsedOffset = [0, 0, 0],
  collapsedRotation = [0, 0, 0],
}: JengaBlock3DProps) => {
  const meshRef = useRef<Mesh>(null);
  const mat = BLOCK_MATERIAL[blockType] ?? BLOCK_MATERIAL.standard;

  // Collapse 여부에 따라 최종 목적지 결정
  const targetPosition: [number, number, number] = isCollapsed
    ? [
        position[0] + collapsedOffset[0],
        position[1] + collapsedOffset[1],
        position[2] + collapsedOffset[2],
      ]
    : position;

  const targetRotation: [number, number, number] = isCollapsed
    ? [
        rotation[0] + collapsedRotation[0],
        rotation[1] + collapsedRotation[1],
        rotation[2] + collapsedRotation[2],
      ]
    : rotation;

  return (
    <motion.mesh
      ref={meshRef as any}
      // 초기 상태: 붕괴가 아니라면 하늘 높은 곳(y+15)에서 시작
      initial={isCollapsed ? false : { 
        x: targetPosition[0], 
        y: targetPosition[1] + 15, 
        z: targetPosition[2], 
        rotateX: rotation[0], 
        rotateY: rotation[1], 
        rotateZ: rotation[2] 
      }}
      animate={{
        x: targetPosition[0],
        y: targetPosition[1],
        z: targetPosition[2],
        rotateX: targetRotation[0],
        rotateY: targetRotation[1],
        rotateZ: targetRotation[2],
      }}
      transition={
        isCollapsed 
          ? { 
              type: 'spring', 
              stiffness: 80, 
              damping: 25, // 붕괴 시 묵직하고 부드러운 산개
              mass: 2.5
            }
          : {
              type: 'spring',
              stiffness: 120, // 쫀득하게 안착
              damping: 14,
              mass: 1.2,
              delay: blockIndex * 0.08, // 0.08초 간격으로 리드미컬하게 스태거링
            }
      }
      castShadow
      receiveShadow
    >
      <boxGeometry args={[3, 1, 1]} />
      <meshToonMaterial color={mat.color} />
      
      {/* 만화/일러스트 스타일용 얇은 외곽선 */}
      <Edges scale={1} threshold={15} color="#4a3b32" />
    </motion.mesh>
  );
};

export default JengaBlock3D;

