import { useQuery } from '@tanstack/react-query';
import { useMemo } from 'react';
import api from '../api/axios';

// ─── 물리 상수 (JengaTower3D와 동기화) ──────────────────────────
const BLOCK_SPACING = 1.05;
const FLOOR_HEIGHT = 1.05;

// ─── 타입 선언 ───────────────────────────────────────────────

interface ApiResponse<T> {
  status: string;
  message: string;
  data: T;
}

export interface ServerBlockData {
  floor_index: number;
  position_index: number;
  block_type: string;
  message: string;
}

export interface ServerTowerData {
  id: number;
  userId: number;
  weekStartDate: string;
  totalFloors: number;
  stabilityScore: number;
  collapsed: boolean;
  blocks: ServerBlockData[];
  createdAt: string;
  updatedAt: string;
}

export interface TransformedBlockData extends ServerBlockData {
  position: [number, number, number];
  rotation: [number, number, number];
}

export interface TransformedTowerData {
  stability_score: number;
  collapsed: boolean;
  total_floors: number;
}

export interface UseTowerDataReturn {
  tower: TransformedTowerData | null;
  blocks: TransformedBlockData[];
  isLoading: boolean;
  isError: boolean;
}

// ─── 좌표 계산 헬퍼 함수 ────────────────────────────────────────
const calcBlockTransform = (floorIndex: number, positionIndex: number): {
  position: [number, number, number];
  rotation: [number, number, number];
} => {
  const isEven = floorIndex % 2 === 0;
  const y = floorIndex * FLOOR_HEIGHT + 0.5;
  const offset = (positionIndex - 1) * BLOCK_SPACING;

  if (isEven) {
    return { position: [0, y, offset], rotation: [0, 0, 0] };
  } else {
    return { position: [offset, y, 0], rotation: [0, Math.PI / 2, 0] };
  }
};

// ─── 커스텀 훅 ───────────────────────────────────────────────

/**
 * @param userId 로그인한 사용자의 ID (AuthContext에서 가져온 값)
 */
export const useTowerData = (userId: number | undefined): UseTowerDataReturn => {

  const fetchMyTower = async (): Promise<ServerTowerData | null> => {
    try {
      // 💡 변경됨: /api/jenga-towers/users/{userId} 엔드포인트 및 공통 api 인스턴스 사용
      const response = await api.get<ApiResponse<ServerTowerData>>(
        `/api/jenga-towers/users/${userId}`
      );
      return response.data?.data ?? null;
    } catch (e) {
      console.warn('Backend server not responding or missing setup:', e);
      return null;
    }
  };

  const { data, isLoading, isError } = useQuery({
    queryKey: ['tower', userId], // userId 기반으로 캐싱
    queryFn: fetchMyTower,
    enabled: !!userId, // userId가 있을 때만 실행
    placeholderData: (prev) => prev,
    staleTime: 1000 * 60 * 5,
  });

  const transformedTower = useMemo<TransformedTowerData | null>(() => {
    if (!data) return null;
    return {
      stability_score: data.stabilityScore,
      collapsed: data.collapsed,
      total_floors: data.totalFloors,
    };
  }, [data]);

  const transformedBlocks = useMemo<TransformedBlockData[]>(() => {
    if (!data || !data.blocks) return [];

    return data.blocks.map((block) => {
      const { position, rotation } = calcBlockTransform(
        block.floor_index, 
        block.position_index
      );
      return {
        ...block,
        position,
        rotation,
      };
    });
  }, [data?.blocks]);

  return {
    tower: transformedTower,
    blocks: transformedBlocks,
    isLoading,
    isError,
  };
};

export default useTowerData;

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Button from '../components/ui/Button';
import Input from '../components/ui/Input';
import { useAuth } from '../contexts/AuthContext';
import AuthLayout from '../layouts/AuthLayout';
import type { ApiResponse, User } from '../types';

const LoginPage = () => {
  const navigate = useNavigate();
  const { login } = useAuth();

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [errorMsg, setErrorMsg] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleLogin = async () => {
    if (!email || !password) {
      setErrorMsg('이메일과 비밀번호를 입력해주세요.');
      return;
    }

    setIsLoading(true);
    setErrorMsg('');

    try {
      const response = await fetch('https://someday-be-production.up.railway.app/api/users/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ email, password }),
      });

      const result: ApiResponse<User> = await response.json();

      if (result.status === 'SUCCESS') {
        const userData = result.data;
        let profileData = null;

        try {
          const profileResponse = await fetch(`https://someday-be-production.up.railway.app/api/my-profiles/${userData.id}`);
          if (profileResponse.ok) {
            const profileDataActual = await profileResponse.json();
            profileData = profileDataActual;
          }
        } catch (profileError) {
          console.error('Failed to fetch profile data:', profileError);
        }

        login(userData, profileData);
        navigate('/main');
      } else {
        setErrorMsg(result.message || '이메일 또는 비밀번호를 확인해주세요.');
      }
    } catch (e) {
      setErrorMsg('서버와 통신하는 중 문제가 발생했습니다.');
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <AuthLayout>
      <div className="bg-white rounded-3xl p-8 shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100">
        <div className="flex flex-col gap-4 mb-2">
          <Input
            id="email"
            type="email"
            label="이메일"
            placeholder="이메일을 입력하세요"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
          <Input
            id="password"
            type="password"
            label="비밀번호"
            placeholder="비밀번호를 입력하세요"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
          {errorMsg && <p className="text-brand-red text-xs font-semibold px-1">{errorMsg}</p>}
          <Button id="login-btn" fullWidth type="submit" disabled={isLoading} className="mt-2 text-[15px] py-[14px]">
            {isLoading ? '로그인 중...' : '로그인'}
          </Button>
        </form>

        {/* 구분선 */}
        <div className="flex items-center gap-3 text-slate-400 text-[13px] my-5 relative">
          <div className="flex-1 h-px bg-slate-200" />
          <span className="font-medium">또는</span>
          <div className="flex-1 h-px bg-slate-200" />
        </div>

        <div className="flex flex-col gap-3">
          <Button id="kakao-login-btn" variant="kakao" fullWidth className="py-3 shadow-sm hover:shadow-md transition-shadow">
            <span className="mr-1">💬</span> 카카오로 시작하기
          </Button>
          <Button id="google-login-btn" variant="google" fullWidth className="py-3 shadow-sm hover:shadow-md transition-shadow">
            <span className="mr-1">🔍</span> Google로 시작하기
          </Button>
        </div>

        <p className="text-center text-slate-500 text-[13px] mt-7">
          아직 계정이 없으신가요?{' '}
          <button id="signup-link" onClick={() => navigate('/signup')} className="text-brand-orange-dark hover:text-brand-orange transition-colors text-[13px] font-bold underline cursor-pointer bg-transparent border-none">
            회원가입
          </button>
        </p>
      </div>
    </AuthLayout>
  );
};

export default LoginPage;

import { useState } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { useTowerData } from '../hooks/useTowerData';

import JengaTower3D from '../components/features/main/JengaTower3D';
import DiaryModal from '../components/features/main/DiaryModal';

type ModalMode = 'diary' | 'survey';

const MainPage = () => {
  const { user } = useAuth();
  
  // Custom hook을 통해 타워/블록 데이터 패치 (user.id 기반)
  const { tower, blocks, isLoading, isError } = useTowerData(user?.id);

  const [modalOpen, setModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState<ModalMode>('diary');

  const openModal = (mode: ModalMode) => {
    setModalMode(mode);
    setModalOpen(true);
  };

  const userName = user?.nickname || user?.name || '사용자';

  // 안정도에 따른 배경색 클래스
  const bgGradient = isStable
    ? 'bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-white/60 via-transparent to-transparent'
    : 'bg-[radial-gradient(ellipse_at_center,_var(--tw-gradient-stops))] from-slate-200/40 via-transparent to-transparent';

  return (
    <>
      <div className={`relative w-full h-screen overflow-hidden transition-colors duration-1000 bg-[#F0ECE4] ${bgGradient}`}>

        {/* 3D 젠가 타워 배경 (Absolute로 전체 화면 점유) */}
        <JengaTower3D tower={TOWER} blocks={BLOCKS} />

        {/* 상단 UI 오버레이 */}
        <div className="absolute top-0 left-0 right-0 z-10 p-5 pt-12 flex flex-col pointer-events-none">
          <div className="flex justify-between items-start mb-2">
            <h1 className={`text-4xl font-extrabold tracking-tighter ${isStable ? 'text-brand-orange-dark' : 'text-slate-800'}`}>
              D-10
            </h1>
            <button className="pointer-events-auto bg-transparent border-none cursor-pointer">
              <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke={isStable ? '#f97316' : '#334155'} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"></path>
                <path d="M13.73 21a2 2 0 0 1-3.46 0"></path>
              </svg>
            </button>
          </div>

          <h2 className={`text-[21px] font-bold leading-tight mb-4 ${isStable ? 'text-brand-orange-dark/80' : 'text-slate-700'}`}>
            {isStable ? '생글생글 웃고있는' : '휴... 기운없는'}<br />
            {userName}님의 타워
          </h2>

          <div className="flex gap-2">
            <button className={`pointer-events-auto flex items-center gap-2 px-3 py-1.5 rounded-full ${isStable ? 'bg-white shadow-sm text-brand-orange-dark border border-brand-orange/20' : 'bg-slate-200 text-slate-700 backdrop-blur-md'} font-bold text-sm border-none cursor-pointer`}>
              📦 블록 쌓기
            </button>
          </div>
        </div>

        {/* 측면 스트레스/안정도 인디케이터 (목업 참조) */}
        <div className="absolute left-5 top-[55%] -translate-y-1/2 z-10 pointer-events-none flex flex-col items-center">
          <div className="w-2.5 h-32 rounded-full overflow-hidden bg-slate-300/50 shadow-inner">
            {/* Score 만큼 바의 높이를 채움. (예: 55%면 높이가 55%이며 아래에서부터 차오름) */}
            <div
              className={`w-full rounded-full transition-all duration-1000 ${isStable ? 'bg-brand-orange shadow-sm' : 'bg-slate-400'}`}
              style={{ height: `${TOWER.stability_score}%`, marginTop: `${100 - TOWER.stability_score}%` }}
            />
          </div>
          <div className="mt-2 text-center">
            <p className="text-[12px] font-extrabold text-slate-800">
              {TOWER.stability_score}%
            </p>
            <p className="text-[10px] font-bold text-slate-500">
              안정도
            </p>
          </div>
        </div>

        {/* 하단 일기 버튼 */}
        <div className="absolute bottom-[90px] left-0 right-0 z-50 flex justify-center pointer-events-none">
          <button
            onClick={() => openModal('diary')}
            className="pointer-events-auto w-[90%] max-w-[400px] flex items-center justify-center gap-2.5 py-4 rounded-xl font-bold text-[16px] border-none shadow-[0_4px_20px_rgba(0,0,0,0.25)] transition-transform hover:-translate-y-0.5 active:translate-y-0 bg-gradient-to-r from-[#8b5e3c] to-[#a8774d] text-white cursor-pointer"
          >
            <span className="text-[18px]">✏️</span>
            오늘 일기 · 마음 살펴보기
          </button>
        </div>
      </div>

      <DiaryModal isOpen={modalOpen} onClose={() => setModalOpen(false)} mode={modalMode} />
    </>
  );
};

export default MainPage;

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import type { MenuItemType } from '../types';
import PageHeader from '../components/layout/PageHeader';
import ProfileCard from '../components/features/my/ProfileCard';
import WeekStress from '../components/features/my/WeekStress';
import MyStats from '../components/features/my/MyStats';
import MenuItem from '../components/features/my/MenuItem';
import Button from '../components/ui/Button';

// ─── 더미 데이터 ──────────────────────────────────────────────
const MENU_ITEMS: MenuItemType[] = [
  { id: 'history', icon: '📊', label: '나의 기록' },
  { id: 'inquiry', icon: '💬', label: '문의하기' },
  { id: 'terms', icon: '📄', label: '이용약관' },
];

const WEEKLY_STRESS_DATA = [
  { day: '월', level: 65 },
  { day: '화', level: 82 },
  { day: '수', level: 45 },
  { day: '목', level: 30 },
  { day: '금', level: 90 },
  { day: '토', level: 25 },
  { day: '일', level: 55 },
];

const getMyProfile = async (userId: number) => {
  const response = await fetch(`https://someday-be-production.up.railway.app/api/my-profiles/${userId}`);
  if (!response.ok) throw new Error('Failed to fetch profile: ' + response.status);
  const result = await response.json();
  return result;
};

const MyPage = () => {
  const navigate = useNavigate();
  const { user, profile, logout, updateProfile } = useAuth();
  const [isAccountModalOpen, setIsAccountModalOpen] = useState(false);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };
  useEffect(() => {
    console.log('MyPage useEffect - user:', user, 'profile:', profile);
    if (user?.id && !profile) {
      console.log('Fetching profile for user ID:', user.id);
      getMyProfile(user.id)
        .then(data => {
          console.log('Profile data fetched successfully:', data);
          if (data) {
            updateProfile(data);
          } else {
            console.warn('Profile data exists but is null/empty');
          }
        })
        .catch(err => {
          console.error('Failed to fetch profile:', err);
        });
    }
  }, [user?.id, profile, updateProfile]);

  return (
    <div className="min-h-screen bg-[#F0ECE4] pb-20 text-slate-800 relative">
      <PageHeader title="마이페이지" gradientColor="orange" />

      {/* 프로필 카드 */}
      <section className="px-5 mb-4">
        <ProfileCard
          name={user?.nickname || user?.name || '사용자님'}
          email={user?.email || 'user@someday.app'}
          avatar={profile?.avatarEmoji || '😊'}
          onEdit={() => setIsAccountModalOpen(true)}
        />
      </section>

      {/* 주간 스트레스 변화 카드 */}
      <section className="px-5 mb-4">
        <WeekStress data={WEEKLY_STRESS_DATA} />
      </section>

      {/* 4가지 요약 통계 */}
      <section className="px-5 mb-4">
        <MyStats
          consecutiveDays={profile?.consecutiveDays || 0}
          towerFloors={profile?.totalLayers || 0}
          receivedCheers={profile?.cheersReceived || 0}
          sentConsoles={profile?.cheersSent || 0}
        />
      </section>

      {/* 메뉴 리스트 */}
      <section className="px-5">
        <div className="bg-white border border-slate-100 rounded-[20px] overflow-hidden shadow-sm">
          {MENU_ITEMS.map((item, i) => (
            <MenuItem
              key={item.id}
              item={item}
              isLast={i === MENU_ITEMS.length - 1}
              onClick={() => {
                if (item.id === 'history') {
                  navigate('/my/records');
                }
              }}
            />
          ))}
        </div>
      </section>

      {/* 계정 설정 모달 */}
      {isAccountModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/30 backdrop-blur-[2px] px-5">
          <div className="bg-white border border-slate-100 rounded-3xl w-full max-w-[360px] p-6 shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-800">계정 설정</h3>
              <button
                onClick={() => setIsAccountModalOpen(false)}
                className="text-slate-400 hover:text-slate-800 transition-colors cursor-pointer text-xl"
              >
                ✕
              </button>
            </div>

            <div className="flex flex-col gap-3">
              <Button variant="ghost" fullWidth className="!justify-start !px-5 text-slate-700 hover:bg-slate-50 border border-transparent hover:border-slate-100">
                <span className="mr-2">🖼️</span> 사용자 프로필 사진 바꾸기
              </Button>
              <Button variant="ghost" fullWidth className="!justify-start !px-5 text-slate-700 hover:bg-slate-50 border border-transparent hover:border-slate-100">
                <span className="mr-2">✏️</span> 닉네임 변경하기
              </Button>
              <Button variant="ghost" fullWidth className="!justify-start !px-5 text-slate-700 hover:bg-slate-50 border border-transparent hover:border-slate-100">
                <span className="mr-2">📧</span> 이메일 변경하기
              </Button>
              <div className="h-px bg-slate-100 my-1" />
              <Button variant="ghost" fullWidth className="!justify-start !px-5 text-slate-700 hover:bg-slate-50 border border-transparent hover:border-slate-100">
                <span className="mr-2">⚙️</span> 시스템 설정
              </Button>
              <Button variant="danger" fullWidth className="!justify-start !px-5" onClick={handleLogout}>
                <span className="mr-2">🚪</span> 로그아웃
              </Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default MyPage;

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import Button from '../components/ui/Button';
import Input from '../components/ui/Input';
import AuthLayout from '../layouts/AuthLayout';

const SignupPage = () => {
  const navigate = useNavigate();

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [nickname, setNickname] = useState('');

  const [errorMsg, setErrorMsg] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSignup = async () => {
    if (!email || !password || !name || !nickname) {
      setErrorMsg('모든 항목을 입력해주세요.');
      return;
    }

    setIsLoading(true);
    setErrorMsg('');

    try {
      const response = await fetch('https://someday-be-production.up.railway.app/api/users/signup', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ email, name, password, nickname }),
      });

      // Status code check since some APIs don't return standard JSON on errors
      if (!response.ok) {
        let msg = '회원가입에 실패했습니다.';
        if (response.status === 500) {
          msg = '서버 오류입니다 (이미 가입된 이메일이거나 서버 내부 문제일 수 있습니다.)';
        }
        try {
          const result = await response.json();
          msg = result.message || msg;
        } catch { } // If JSON parse fails, fallback to default msg
        setErrorMsg(msg);
        setIsLoading(false);
        return;
      }

      const result = await response.json();

      // If backend returns a standardized { status: 'SUCCESS' }
      if (result.status === 'SUCCESS' || response.ok) {
        alert('회원가입이 완료되었습니다. 로그인해주세요.');
        navigate('/login');
      } else {
        setErrorMsg(result.message || '회원가입에 실패했습니다.');
      }
    } catch (e) {
      setErrorMsg('서버와 통신하는 중 문제가 발생했습니다.');
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <AuthLayout>
      <div className="bg-white rounded-3xl p-8 shadow-[0_8px_30px_rgb(0,0,0,0.04)] border border-slate-100">
        <h2 className="text-xl font-extrabold text-slate-800 mb-6 text-center">회원가입</h2>

        <div className="flex flex-col gap-4 mb-2">
          <Input
            id="email"
            type="email"
            label="이메일"
            placeholder="example@someday.app"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
          <Input
            id="name"
            type="text"
            label="이름"
            placeholder="본명을 입력하세요"
            value={name}
            onChange={(e) => setName(e.target.value)}
          />
          <Input
            id="nickname"
            type="text"
            label="닉네임"
            placeholder="앱에서 사용할 닉네임"
            value={nickname}
            onChange={(e) => setNickname(e.target.value)}
          />
          <Input
            id="password"
            type="password"
            label="비밀번호"
            placeholder="안전한 비밀번호를 입력하세요"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSignup()}
          />

          {errorMsg && <p className="text-brand-red text-xs font-semibold px-1 mt-1">{errorMsg}</p>}

          <Button id="signup-btn" fullWidth onClick={handleSignup} disabled={isLoading} className="mt-4 text-[15px] py-[14px]">
            {isLoading ? '가입 중...' : '시작하기'}
          </Button>
        </div>

        <p className="text-center text-slate-500 text-[13px] mt-7">
          이미 계정이 있으신가요?{' '}
          <button id="login-link" onClick={() => navigate('/login')} className="text-brand-orange-dark hover:text-brand-orange transition-colors text-[13px] font-bold underline cursor-pointer bg-transparent border-none">
            로그인하기
          </button>
        </p>
      </div>
    </AuthLayout>
  );
};

export default SignupPage;
